#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

rfl::Result<Nothing> delete_inactive_users() {
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return conn_result.error();
  }
  auto conn = *conn_result;

  // 2. Begin a transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return begin_result.error();
  }

  // 3. Delete users where last_login is before 2025-01-01
  auto delete_result = (sqlgen::delete_from<User> | sqlgen::where("last_login"_c < "2025-01-01"))(conn);
  if (!delete_result) {
    // Rollback on failure
    auto rollback_result = sqlgen::rollback(conn);
    if (!rollback_result) {
      return rfl::error("Delete failed and rollback also failed");
    }
    return delete_result.error();
  }

  // 4. Commit the transaction
  auto commit_result = sqlgen::commit(conn);
  if (!commit_result) {
    // Rollback on commit failure
    auto rollback_result = sqlgen::rollback(conn);
    if (!rollback_result) {
      return rfl::error("Commit failed and rollback also failed");
    }
    return commit_result.error();
  }

  // 5. Return the result of the commit operation
  return commit_result;
}

} // namespace delete_inactive_users
```

