TEST(sqlite, CalculateOrderMetrics) {
  std::vector<OrderItem> items = {
      {1, 101, 201, 100.0, 5, 10.0, 5.0}, // Normal item
      {2, 101, 202, 50.0, 12, std::nullopt, std::nullopt}, // Null discount/tax, modulo test (12 % 10 = 2)
